changeSet.sql:
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = '${app_role_name}') THEN
        EXECUTE format('CREATE ROLE %I LOGIN PASSWORD %L', '${app_role_name}', '${app_role_password}');
    END IF;
END
$$;

GRANT USAGE ON SCHEMA public TO ${app_role_name};
-- Default deny, then grant the minimum each table class needs. REVOKE ALL ON ALL TABLES IN SCHEMA public FROM ${app_role_name};
-- Regulated MUTABLE tables: SELECT, INSERT, UPDATE (NO DELETE -> soft delete only). GRANT SELECT, INSERT, UPDATE ON sites, departments, roles, permissions, users, user_roles, role_permissions, attachments, record_sequences, documents, document_read_assignments, change_controls, capas, capa_actions, deviations, products, materials, batch_records, batch_production_steps, batch_materials_used, batch_qc_results, batch_deviations_link, batch_products_produced, notifications, complaints, complaint_investigation, complaint_resolution, complaint_capa_link, complaint_timeline, audits, audit_findings, audit_capa_link, audit_follow_up, risks, risk_analysis, risk_mitigation, risk_control_effectiveness, suppliers, supplier_qualifications, supplier_certifications, supplier_performance, supplier_findings, supplier_capa_link, training_programs, training_assignments, training_auto_rules, training_completion_audit, equipment, calibrations, maintenance_history, equipment_specifications, oos_cases, oos_initial_assessment, oos_repeat_testing, oos_investigation, oos_disposition, oos_capa_link, non_conformances, non_conformance_investigation, non_conformance_disposition, non_conformance_use_as_is_approval, non_conformance_capa_link, management_reviews, review_metrics, review_audit_results, review_product_feedback, review_action_items, review_decisions TO ${app_role_name};
-- Append-only audit trail: SELECT + INSERT only. GRANT SELECT, INSERT ON audit_logs TO ${app_role_name};
-- Immutable signatures: SELECT + INSERT only. GRANT SELECT, INSERT ON electronic_signatures TO ${app_role_name};
-- Identity-column / sequence usage. GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO ${app_role_name};
